def ensure_index(es: Elasticsearch, index: str, mappings: Dict[str, Any], settings: Optional[Dict[str, Any]] = None) -> None:
    if es.indices.exists(index=index):
        return
    body: Dict[str, Any] = {"mappings": mappings}
    if settings:
        body["settings"] = settings
    es.indices.create(index=index, **body)


def ensure_alias(es: Elasticsearch, index: str, alias: str, is_write_index: Optional[bool] = None) -> None:
    actions = []
    if not es.indices.exists_alias(name=alias):
        action = {"add": {"index": index, "alias": alias}}
        if is_write_index is not None:
            action["add"]["is_write_index"] = is_write_index
        actions.append(action)
    else:
        existing = es.indices.get_alias(name=alias)
        if index not in existing:
            action = {"add": {"index": index, "alias": alias}}
            if is_write_index is not None:
                action["add"]["is_write_index"] = is_write_index
            actions.append(action)
    if actions:
        es.indices.update_aliases(body={"actions": actions})


