    s.add_argument("--sort", default=None, help="Sort field; prefix with - for desc (default: -@timestamp)")
    s.set_defaults(func=cmd_search_docs)

    s = sub.add_parser("emit-log", help="Emit a log event to the logs write alias (rollover)")
    s.add_argument("message")
