    s.add_argument("--level", default=None)
    s.add_argument("--filter", nargs="*", default=None, help="Additional filters as key=value")
    s.add_argument("--start", default=None, help="Start time for @timestamp (ISO8601)")
    s.add_argument("--end", default=None, help="End time for @timestamp (ISO8601)")
